import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import Header from './components/Header'; // Import the Header component
import Home from './components/Home';
import Upload from './components/Upload';
import Results from './components/Results';
import ImageProject from './components/ImageProject';
import AudioProject from './components/AudioProject';
import PoseProject from './components/PoseProject';

const App = () => {
    return (
        <Router>
            <div>
                <Header /> {/* Render the Header component */}

                <Routes>
                    <Route path="/" element={<Home />} />
                    <Route path="/upload" element={<Upload />} />
                    <Route path="/results" element={<Results />} />
                    <Route path="/image-project" element={<ImageProject />} />
                    <Route path="/audio-project" element={<AudioProject />} />
                    <Route path="/pose-project" element={<PoseProject />} />
                </Routes>
            </div>
        </Router>
    );
};

export default App;
